<template>
	<view>
		<page-head title="websocketйҖҡи®ҜзӨәдҫӢ"></page-head>
		<view class="uni-padding-wrap">
			<view class="uni-btn-v">
				<view class="websocket-msg">{{showMsg}}</view>
				<button type="primary" @click="connect">иҝһжҺҘwebsocketжңҚеҠЎ</button>
				<button v-show="connected" type="primary" @click="send">еҸ‘йҖҒдёҖжқЎж¶ҲжҒҜ</button>
				<button type="primary" @click="close">ж–ӯејҖwebsocketжңҚеҠЎ</button>
				<view class="websocket-tips">еҸ‘йҖҒж¶ҲжҒҜеҗҺдјҡж”¶еҲ°дёҖжқЎжңҚеҠЎеҷЁиҝ”еӣһзҡ„ж¶ҲжҒҜпјҲдёҺеҸ‘йҖҒзҡ„ж¶ҲжҒҜеҶ…е®№дёҖиҮҙпјү</view>
			</view>
		</view>
	</view>
</template>

<script>
	let platform = uni.getSystemInfoSync().platform
	export default {
		data() {
			return {
				connected: false,
				connecting: false,
				socketTask: false,
				msg: false,
			}
		},
		computed: {
			showMsg() {
				if (this.connected) {
					if (this.msg) {
						return 'ж”¶еҲ°ж¶ҲжҒҜпјҡ' + this.msg
					} else {
						return 'зӯүеҫ…жҺҘж”¶ж¶ҲжҒҜ'
					}
				} else {
					return 'е°ҡжңӘиҝһжҺҘ'
				}
			}
		},
		onUnload() {
            uni.hideLoading()
			if (this.socketTask && this.socketTask.close) {
				this.socketTask.close()
			}
		},
		methods: {
			connect() {
				if (this.connected || this.connecting) {
					uni.showModal({
						content: 'жӯЈеңЁиҝһжҺҘжҲ–иҖ…е·Із»ҸиҝһжҺҘпјҢиҜ·еӢҝйҮҚеӨҚиҝһжҺҘ',
						showCancel: false
					})
					return false
				}
				this.connecting = true
				uni.showLoading({
					title: 'иҝһжҺҘдёӯ...'
				})
				this.socketTask = uni.connectSocket({
					url: 'wss://echo.websocket.org',
					data() {
						return {
							msg: 'Hello'
						}
					},
					// #ifdef MP
					header: {
						'content-type': 'application/json'
					},
					// #endif
					// #ifdef MP-WEIXIN
					method: 'GET',
					// #endif
					success(res) {
						// иҝҷйҮҢжҳҜжҺҘеҸЈи°ғз”ЁжҲҗеҠҹзҡ„еӣһи°ғпјҢдёҚжҳҜиҝһжҺҘжҲҗеҠҹзҡ„еӣһи°ғпјҢиҜ·жіЁж„Ҹ
					},
					fail(err) {
						// иҝҷйҮҢжҳҜжҺҘеҸЈи°ғз”ЁеӨұиҙҘзҡ„еӣһи°ғпјҢдёҚжҳҜиҝһжҺҘеӨұиҙҘзҡ„еӣһи°ғпјҢиҜ·жіЁж„Ҹ
					}
				})
                console.log(this.socketTask);
				this.socketTask.onOpen((res) => {
					this.connecting = false
					this.connected = true
					uni.hideLoading()
					uni.showToast({
						icon: 'none',
						title: 'иҝһжҺҘжҲҗеҠҹ'
					})
					console.log('onOpen', res);
				})
				this.socketTask.onError((err) => {
					this.connecting = false
					this.connected = false
					uni.hideLoading()
					uni.showModal({
						content: 'иҝһжҺҘеӨұиҙҘпјҢеҸҜиғҪжҳҜwebsocketжңҚеҠЎдёҚеҸҜз”ЁпјҢиҜ·зЁҚеҗҺеҶҚиҜ•',
						showCancel: false
					})
					console.log('onError', err);
				})
				this.socketTask.onMessage((res) => {
					this.msg = res.data
					console.log('onMessage', res)
				})
				this.socketTask.onClose((res) => {
					this.connected = false
					this.startRecive = false
					this.socketTask = false
					this.msg = false
					console.log('onClose', res)
				})
				console.log('task', this.socketTask)
			},
			send() {
				this.socketTask.send({
					data: 'from ' + platform + ' : ' + parseInt(Math.random() * 10000).toString(),
					success(res) {
						console.log(res);
					},
					fail(err) {
						console.log(err);
					}
				})
			},
			close() {
				if (this.socketTask && this.socketTask.close) {
					this.socketTask.close()
				}
			}
		}
	}
</script>

<style>
	
	.uni-btn-v {
		padding: 10rpx 0;
	}

	.uni-btn-v button {
		margin: 20rpx 0;
	}

	.websocket-msg {
		padding: 40px 0px;
		text-align: center;
		font-size: 14px;
		line-height: 40px;
		color: #666666;
	}

    .websocket-tips{
        padding: 40px 0px;
        text-align: center;
        font-size: 14px;
        line-height: 24px;
        color: #666666;
    }
</style>
